    <aside class="catalog-sidebar">
        <h5>Filters</h5>

        <div class="filter-section">
            <label class="fw-semibold mb-1">Category</label>
            @if (_categories is null)
            {
                <p class="text-muted small">Loading categories…</p>
            }
            else
            {
                @foreach (var category in _categories)
                {
                    <div class="form-check">
                        <input class="form-check-input darker-border-checkbox"
                               type="checkbox"
                               id="@($"cat-{category}")"
                               checked="@(_selectedCategories.Contains(category))"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                    </div>
                }
            }
        </div>

        <div class="filter-section">
            <label class="fw-semibold mb-1">Price Range</label>
            <div class="d-flex gap-2 align-items-center">
                <input type="number" class="form-control form-control-sm" placeholder="Min"
                       @bind="_minPrice" @bind:event="oninput" min="0" step="0.01" />
                <span>–</span>
                <input type="number" class="form-control form-control-sm" placeholder="Max"
                       @bind="_maxPrice" @bind:event="oninput" min="0" step="0.01" />
            </div>
        </div>

        <div class="filter-section">
            <div class="form-check">
                <input class="form-check-input darker-border-checkbox" type="checkbox"
                       id="inStockOnly" @bind="_inStockOnly" />
                <label class="form-check-label" for="inStockOnly">In Stock Only</label>
            </div>
        </div>

        <div class="d-grid gap-2">
            <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <section class="catalog-main">
        <!-- Toolbar -->
        <div class="catalog-toolbar">
            <div class="d-flex align-items-center gap-2">
                <label class="form-label mb-0 text-nowrap" for="sortBy">Sort by:</label>
                <select class="form-select form-select-sm" id="sortBy" style="width: auto;"
                        @bind="_sortBy" @bind:after="OnSortChanged">
                    <option value="price_asc">Price: Low to High</option>
                    <option value="price_desc">Price: High to Low</option>
                    <option value="name_asc">Name: A–Z</option>
                    <option value="rating_desc">Rating: Highest</option>
                </select>
            </div>
            @if (_result is not null)
            {
                var first = (_result.Page - 1) * _result.PageSize + 1;
                var last = Math.Min(_result.Page * _result.PageSize, _result.TotalCount);
                <span class="text-muted small">Showing @first–@last of @_result.TotalCount products</span>
            }
        </div>

        <!-- Product Grid / States -->
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
                <span class="ms-2">Loading products…</span>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="text-center py-5 text-muted">
                <h5>No products found</h5>
                <p>Try adjusting your filters or clearing them.</p>
            </div>
        }
        else
        {
            <div class="product-grid">
                @foreach (var product in _result.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="OnProductSelected"
                                 OnAddToCart="OnAddToCart" />
                }
            </div>

            <!-- Pagination -->
            @{
                var totalPages = (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);
            }
            @if (totalPages > 1)
            {
                <nav aria-label="Product pagination" class="mt-3">
                    <ul class="pagination justify-content-center mb-0">
                        <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                    disabled="@(_currentPage == 1)">Previous</button>
                        </li>
                        @for (var p = 1; p <= totalPages; p++)
                        {
                            var pageNum = p;
                            <li class="page-item @(pageNum == _currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(_currentPage == totalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                    disabled="@(_currentPage == totalPages)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </section>
</div>

@code {
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            await Task.WhenAll(categoriesTask, searchTask);
            _categories = await categoriesTask;
        }
        catch (Exception ex)
        {
            _error = $"Failed to load catalog: {ex.Message}";
            _loading = false;
        }
    }

    private async Task SearchProductsAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var filter = new ProductFilter(
                Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                MinPrice: _minPrice,
                MaxPrice: _maxPrice,
                InStockOnly: _inStockOnly
            );

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = $"Failed to load products: {ex.Message}";
            _result = null;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task OnSortChanged()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        _currentPage = page;
        await SearchProductsAsync();
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level handler — navigate to detail page
        // Navigation would be injected and used here in a full app
    }

    private void OnAddToCart(Product product)
    {
        // Handle add-to-cart logic
    }
}

